-- ==========================================
-- FREQUENTLY ASKED QUESTIONS
-- ==========================================
P.FAQ = {
    {
        q = "How do I move UI elements? (e.g.Player Frame, Party Frame, Cast Bar, etc...)",
        a = "OakUI heavily relies on QUI's Anchoring system and this is why elements say LOCKED in edit mode. To move them, go to QUI's Layout Mode (/qui layout) and you can move any elements by holding shift and dragging them. You can also right click on any element to change it's settings.",
        quiTab = "Anchoring & Layout",
        quiAction = "layout",
    },
	{
        q = "How do I resize, move, add more, or remove my Action Bars?",
        a = "Action bars are now controlled in QUI's Layout Mode (/qui layout). Open Layout Mode, then right click any action bar to change its layout, number of buttons, visibility, or other settings.",
        quiTab = "Anchoring & Layout",
        quiAction = "layout",
    },
    {
        q = "How do I enable/disable different addon elements (e.g. The Mythic+ Timer, Action Tracker, Focus Unitframe, Etc...)",
        a = "Enabling UI elements is all handled in the QUI Layout Mode (/qui layout). Simply open layout mode and look on the right or left edge of the screen for a 'Edit Mode' button (it will have a flashing border), click it, and then click frames. There are several sections where you can turn different elements on (enable) or off (disable).",
        quiTab = "Anchoring & Layout",
        quiAction = "layout",
    },
	{
        q = "How do I change the size of my Party or Raid frames?",
        a = "If you are using the primary OAK UI setup, your group frames are handled by QUI. Open Layout Mode (/qui layout) right click on the party frames or raid frames and you can adjust the width, height, and display conditions.",
        quiTab = "Group Frames",
        quiAction = "layout",
    },
	{
        q = "Why do I see multiple party frames?",
        a = "OakUI has moved away from using the Danders Frames addon and instead uses QUI's built in Party & Raid Frames. If you see multiple party frames, you will need to disable Danders Frames, OR, Alternatively disable QUI's party/raid frames.", 
		quiTab = "Group Frames",
        quiAction = "settings",
    },
	{
        q = "How do I adjust the font size of the objective/quest tracker?",
        a = "Open QUI's Layout Mode (/qui layout) and right click on the objective tracker, then select Text. There you can change the Objective Text Font and Module Header Font.", 
		quiTab = "Skinning & Autohide",
        quiAction = "layout",
    },
    {
        q = "My UI looks like a mess and everything is overlapping. What did I miss?",
        a = "You likely missed STEP 1 of the installation! You must click 'Copy Layout' on the Blizzard Edit Mode row, open WoW's Edit Mode (Esc -> Edit Mode), click Import, and paste the string to position the base frames correctly."
    },
    {
        q = "How do I get the custom font to show up on the 3D names floating above players?",
        a = "Due to WoW engine limitations, addons cannot change 3D world text automatically. You must install the font manually. Go to the 'Custom Fonts' tab in this installer and follow the 4 simple steps."
    },
    {
        q = "Why are my chat windows missing tabs or positioned weirdly?",
        a = "Simply click the 'Apply Layout' button next to the OakUI Chat Layout row in the installer. This will instantly snap your chat windows back into the intended OAK format with the correct General and Loot tabs."
    }
}

